fn solve(s: String, order: Vec<i64>, k: i64) -> i64 {
    let n = s.len();
    if k == 0 {
        return 0;
    }
    let total_substrings = n as i64 * (n as i64 + 1) / 2;
    if k > total_substrings {
        return -1;
    }

    let mut marked = vec![false; n];
    let mut current_valid = 0;
    let s_chars: Vec<char> = s.chars().collect();

    for t in 0..order.len() {
        let idx = order[t] as usize;
        if !marked[idx] {
            marked[idx] = true;
            let mut left = idx as i64 - 1;
            while left >= 0 && !marked[left as usize] {
                left -= 1;
            }
            let left_bound = left + 1;
            let mut right = idx as i64 + 1;
            while right < n as i64 && !marked[right as usize] {
                right += 1;
            }
            let right_bound = right - 1;
            let new_valid = (idx as i64 - left_bound) * (right_bound - idx as i64 + 1);
            current_valid += new_valid;
            if current_valid >= k {
                return t as i64 + 1;
            }
        }
    }
    -1
}
